Browser 版<br />
<pre><code data-type="js">const myHeaders = new Headers();
myHeaders.append(&quot;Content-Type&quot;, &quot;application/x-www-form-urlencoded&quot;);
myHeaders.append(&quot;Authorization&quot;, &quot;Bearer 你條KEY&quot;);

const formdata = new FormData();
formdata.append(&quot;lang&quot;, &quot; 1&quot;);
formdata.append(&quot;token&quot;, &quot; 88recaptcha&quot;);

const requestOptions = {
  method: 'POST',
  headers: myHeaders,
  body: formdata,
  redirect: 'follow'
};
for(;;) { // 神 loop
  fetch(&quot;https://www.hknycd.com/api/v1/card-game-redeem&quot;, requestOptions)
    .then(response =&gt; response.text())
    .then(result =&gt; console.log(result))
    .catch(error =&gt; console.log('error', error));
}</code></pre>

